<?php
require dirname(__DIR__) . '/src/bootstrap.php';
require_admin();$event=$pdo->query("SELECT * FROM eventos WHERE slug='carrera-5k-policia-2026' LIMIT 1")->fetch();$stmt=$pdo->prepare('SELECT i.codigo,i.identificacion,i.primer_nombre,i.segundo_nombre,i.primer_apellido,i.segundo_apellido,i.fecha_nacimiento,i.edad_evento,i.sexo,i.correo,i.telefono,i.contacto_emergencia,i.telefono_emergencia,i.talla_camiseta,c.nombre categoria,i.estado,p.nombre_titular,p.referencia,p.fecha_pago,p.monto,p.estado estado_pago,i.creado_en FROM inscripciones i JOIN categorias c ON c.id=i.categoria_id JOIN pagos p ON p.inscripcion_id=i.id WHERE i.evento_id=? ORDER BY i.id');$stmt->execute([$event['id']]);header('Content-Type: text/csv; charset=UTF-8');header('Content-Disposition: attachment; filename="inscripciones-carrera5k-'.date('Ymd-His').'.csv"');echo "\xEF\xBB\xBF";$out=fopen('php://output','w');fputcsv($out,['codigo','identificacion','primer_nombre','segundo_nombre','primer_apellido','segundo_apellido','fecha_nacimiento','edad_evento','sexo','correo','telefono','contacto_emergencia','telefono_emergencia','talla_camiseta','categoria','estado','nombre_titular','referencia','fecha_pago','monto','estado_pago','creado_en']);while($row=$stmt->fetch()){fputcsv($out,$row);}fclose($out);exit;
